1	//! Locale-aware text case transformation helpers.
2	//!
3	//! Rust's built-in Unicode case conversion is locale-independent, which means
4	//! it misses language-sensitive mappings such as Turkish dotted and dotless I
5	//! and Greek final sigma handling. These helpers delegate to ICU4X
6	//! [`CaseMapper`](icu::casemap::CaseMapper) or the browser's locale-aware
7	//! string APIs so components can apply the spec-defined behavior consistently
8	//! across backends.
9	
10	use alloc::string::String;
11	
12	#[cfg(feature = "icu4x")]
13	use icu::casemap::CaseMapper;
14	#[cfg(all(feature = "web-intl", target_arch = "wasm32", not(feature = "icu4x")))]
15	use js_sys::JsString;
16	
17	use crate::Locale;
18	
19	/// Locale-aware uppercase transformation.
20	///
21	/// Delegates to ICU4X [`CaseMapper`] so locale-specific mappings such as
22	/// Turkish dotted capital I are preserved. Under the wasm `web-intl` backend,
23	/// this delegates to browser `String.prototype.toLocaleUpperCase()`. On
24	/// non-wasm builds with `web-intl`, it falls back to Unicode case conversion so
25	/// the public API remains available in feature-matrix builds.
26	#[must_use]
27	#[cfg(feature = "icu4x")]
28	pub fn to_uppercase(text: &str, locale: &Locale) -> String {
29	    CaseMapper::new()
30	        .uppercase_to_string(text, locale.language_identifier())
31	        .into_owned()
32	}
33	
34	/// Locale-aware uppercase transformation.
35	///
36	/// Delegates to browser `String.prototype.toLocaleUpperCase()` on wasm
37	/// `web-intl` builds.
38	#[must_use]
39	#[cfg(all(feature = "web-intl", target_arch = "wasm32", not(feature = "icu4x")))]
40	pub fn to_uppercase(text: &str, locale: &Locale) -> String {
41	    let locale_tag = locale.to_bcp47();
42	    String::from(JsString::from(text).to_locale_upper_case(Some(locale_tag.as_str())))
43	}
44	
45	/// Locale-aware uppercase transformation.
46	///
47	/// Non-wasm `web-intl` builds cannot access the browser `Intl` APIs, so this
48	/// falls back to Rust's Unicode case mapping while preserving the shared public
49	/// API surface.
50	#[must_use]
51	#[cfg(all(
52	    feature = "web-intl",
53	    not(target_arch = "wasm32"),
54	    not(feature = "icu4x")
55	))]
56	pub fn to_uppercase(text: &str, _locale: &Locale) -> String {
57	    text.to_uppercase()
58	}
59	
60	/// Locale-aware lowercase transformation.
61	///
62	/// Delegates to ICU4X [`CaseMapper`] so locale-specific mappings such as
63	/// Turkish dotless i and Greek final sigma are preserved. Under the wasm
64	/// `web-intl` backend, this delegates to browser
65	/// `String.prototype.toLocaleLowerCase()`. On non-wasm builds with `web-intl`,
66	/// it falls back to Unicode case conversion so the public API remains
67	/// available in feature-matrix builds.
68	#[must_use]
69	#[cfg(feature = "icu4x")]
70	pub fn to_lowercase(text: &str, locale: &Locale) -> String {
71	    CaseMapper::new()
72	        .lowercase_to_string(text, locale.language_identifier())
73	        .into_owned()
74	}
75	
76	/// Locale-aware lowercase transformation.
77	///
78	/// Delegates to browser `String.prototype.toLocaleLowerCase()` on wasm
79	/// `web-intl` builds.
80	#[must_use]
81	#[cfg(all(feature = "web-intl", target_arch = "wasm32", not(feature = "icu4x")))]
82	pub fn to_lowercase(text: &str, locale: &Locale) -> String {
83	    let locale_tag = locale.to_bcp47();
84	    String::from(JsString::from(text).to_locale_lower_case(Some(locale_tag.as_str())))
85	}
86	
