228	    /// Find the first item whose `text_value` starts with `search` using
229	    /// locale-aware case folding via ICU4X `CaseMapper`, beginning the search
230	    /// from the item *after* `current_focus` (single-char, cycling) or *at*
231	    /// `current_focus` (multi-char, refining).
232	    ///
233	    /// Single-character searches wrap; multi-character searches do not (they
234	    /// stay within the current alphabetical run to avoid disorienting jumps).
235	    #[cfg(feature = "i18n")]
236	    fn find_match<T, C: Collection<T>>(
237	        search: &str,
238	        current_focus: Option<&Key>,
239	        collection: &C,
240	        locale: &Locale,
241	        disabled_keys: &BTreeSet<Key>,
242	        disabled_behavior: DisabledBehavior,
243	    ) -> Option<Key> {
244	        // CaseMapper::new() returns CaseMapperBorrowed<'static> which is Copy —
245	        // no caching needed, can be constructed freely.
246	        let case_mapper = icu::casemap::CaseMapper::new();
247	
248	        let langid = locale.language_identifier();
249	
250	        // Determine single-char mode from the raw input, not the lowercased
251	        // query — one typed character can expand to multiple scalars after case
252	        // mapping (e.g., İ → i + combining dot in non-Turkish locales).
253	        let single_char = search.chars().count() == 1;
254	
255	        let query = case_mapper.lowercase_to_string(search, langid);
256	
257	        // FocusOnly: disabled items are focusable, so include them in the scan.
258	        // Skip: disabled items are excluded from the scan.
259	        let skip_disabled = disabled_behavior == DisabledBehavior::Skip;
260	
261	        let all_item_keys = collection
262	            .nodes()
263	            .filter(|n| n.is_focusable() && (!skip_disabled || !disabled_keys.contains(&n.key)))
264	            .map(|n| n.key.clone())
265	            .collect::<Vec<_>>();
266	
267	        if all_item_keys.is_empty() {
268	            return None;
269	        }
