    }

    #[test]
    fn ignore_case_false_matches_case_sensitive() {
        let props = Props::new()
            .query(["hello"])
            .text("HELLO world")
            .ignore_case(false);

        let chunks = highlight_chunks(&props, &en_us());

        assert_eq!(
